import httpx

BACKSTAGE = "https://backstage.internal/api/catalog"

def check_active_consumers(component_name: str) -> list[str]:
    """Return a list of component names that still depend on this component."""
    resp = httpx.get(
        f"{BACKSTAGE}/entities",
        params={
            "kind": "Component",
            "filter": f"spec.dependsOn=component:default/{component_name}",
        },
        headers={"Authorization": f"Bearer {TOKEN}"},
    )
    resp.raise_for_status()
    return [e["metadata"]["name"] for e in resp.json()]

def decommission(component_name: str, dry_run: bool = True) -> None:
    consumers = check_active_consumers(component_name)
    if consumers:
        raise RuntimeError(
            f"Cannot decommission: {len(consumers)} active consumer(s): {consumers}"
        )
    if dry_run:
        print(f"[DRY RUN] Would archive {component_name}")
        return
    # Archive: set lifecycle to end-of-life and remove from active index
    # (actual catalog API call omitted — varies by Backstage version)
    print(f"Decommissioned: {component_name}")

# Run from the decommission GitHub Actions workflow
if __name__ == "__main__":
    import sys
    decommission(sys.argv[1], dry_run="--dry-run" in sys.argv)

import httpx
from collections import defaultdict

BACKSTAGE  = "https://backstage.internal/api/catalog"
GATEWAY_ANALYTICS = "https://analytics.internal/api/gateway-calls"

def consumer_impact_report(component_name: str, lookback_days: int = 30) -> dict:
    # 1. Catalog dependsOn graph
    catalog_consumers = _catalog_consumers(component_name)

    # 2. Gateway traffic (teams calling the API in the last N days)
    traffic_consumers = _gateway_consumers(component_name, lookback_days)

    # Combined — union of both sources
    all_consumers = {
        c: {
            "in_catalog": c in catalog_consumers,
            "in_traffic": c in traffic_consumers,
            "calls_per_day": traffic_consumers.get(c, {}).get("calls_per_day", 0),
        }
        for c in set(catalog_consumers) | set(traffic_consumers)
    }
    return {
        "component":      component_name,
        "total_consumers": len(all_consumers),
        "consumers":      all_consumers,
        "safe_to_deprecate": len(all_consumers) == 0,
    }

def _catalog_consumers(name: str) -> list[str]:
    resp = httpx.get(
        f"{BACKSTAGE}/entities",
        params={"kind": "Component",
                "filter": f"spec.dependsOn=component:default/{name}"},
        headers={"Authorization": f"Bearer {TOKEN}"},
    )
    return [e["metadata"]["name"] for e in resp.json()]

def _gateway_consumers(name: str, days: int) -> dict[str, dict]:
    resp = httpx.get(
        f"{GATEWAY_ANALYTICS}/by-upstream",
        params={"upstream": name, "days": days},
        headers={"Authorization": f"Bearer {TOKEN}"},
    )
    return {r["caller_service"]: r for r in resp.json().get("callers", [])}
